// First fetch all required data
function fetchAllData() {
  return queries.fetchConfigValues.run({}, {
    onSuccess: (configValues) => {
      if (page.variables.isTestEnvironment) {
        queries.downloadBackupFileEnv.run({
          onSuccess: (data) => {
            return calculateRollbackDiff(configValues, data);
          },
          onFailure: () => {
            actions.setPageVariable("rollbackDiffArray", []);
            actions.setPageVariable("rollbackDiffTableColumns", []);
          }
        });
      } else {
        queries.downloadBackupFile.run({
          onSuccess: (data) => {
            return calculateRollbackDiff(configValues, data);
          },
          onFailure: () => {
            actions.setPageVariable("rollbackDiffArray", []);
            actions.setPageVariable("rollbackDiffTableColumns", []);
          }
        });
      }
    },
    onFailure: () => {
      actions.setPageVariable("rollbackDiffArray", []);
      actions.setPageVariable("rollbackDiffTableColumns", []);
    }
  });
}


function calculateRollbackDiff(configValues, data) {
  const currentConfigDimensions = queries.fetchConfigDetails.data.Dimensions;
  // Step 1: Get dimensions from currentConfigDimensions
  const dimensions = currentConfigDimensions.map(dim => dim.dimension_name);

  // Set rollbackDiffTableColumns
  const tempColumns = {
    "newValue": {
      "name" : "New Value"
    },
    "currentValue": {
      "name" : "Current Value"
    },
    "isSame": {
      "name": "Is Same"
    }
  };
  // Add dimension columns dynamically
  currentConfigDimensions.forEach(dimension => {
    tempColumns[dimension.dimension_name] = {
      "name": dimension.dimension_name
    };
  });
  actions.setPageVariable("rollbackDiffTableColumns", tempColumns);

  // Step 2: Process current config values
  const currentConfigRows = configValues.map(config => {
    const row = {
      newValue: "",
      currentValue: formatValue(config.value),
    };

    // Add dimension columns with current values
    config.dimensions.forEach(dim => {
      row[dim.dimension_name] =  dim[dim.value];
    });

    // Add empty values to dimensions not found
    dimensions.forEach(dim => {
      row[dim] =  row[dim] || "-";
    });

    return row;
  });

  // Step 3: Process rollback values from CSV
  const rollbackData = data.message;
  const rollbackRows = parseCSVToObjects(rollbackData, dimensions);

  // Step 4: Create final diff array
  const rollbackDiffArrayTemp = mergeCurrentAndRollbackData(currentConfigRows, rollbackRows, dimensions);

  // Step 5: Set the rollbackDiffArray variable in Retool
  actions.setPageVariable("rollbackDiffArray", rollbackDiffArrayTemp);

  return rollbackDiffArrayTemp;
}

function parseCSVToObjects(csvData, dimensions) {
    const rows = csvData.trim().split('\n');
    const valueType = queries.fetchConfigDetails.data["Value Type"];

    return rows.slice(1).map(row => {
        const values = parseCSVRow(row);
        let rawValue = values[0];
        let formattedData = rawValue; // Default to rawValue
        // Check if valueType contains "ARRAY"
        if (valueType?.includes("ARRAY")) {
            formattedData = formatString(rawValue);
            if(valueType === "STRING_ARRAY") {
              formattedData = JSON.stringify(formatString(rawValue));
            }
        }

        const obj = {
            newValue: formattedData,
            currentValue: ""
        };

        dimensions.forEach((dim, index) => {
            obj[dim] = values[index + 1] || '-';
        });

        return obj;
    });
}

function parseCSVRow(row) {
    let values = [];
    let currentValue = '';
    let inQuotes = false;

    for (let char of row) {
        if (char === '"') {
            inQuotes = !inQuotes;
        }
        if (char === ',' && !inQuotes) {
            values.push(currentValue);
            currentValue = '';
        } else {
            currentValue += char;
        }
    }
    values.push(currentValue); // Add the last value
    return values;
}

function formatString(str) {
    if (str.startsWith('"') && str.endsWith('"')) {
        try {
            // Remove the outer double quotes
            let jsonStr = str.slice(1, -1);

            // Remove the extra double quotes surrounding the array elements
            jsonStr = jsonStr.replace(/""([^""]+)""/g, '"$1"');

            // Parse the cleaned JSON string
            return JSON.parse(jsonStr);
        } catch (e) {
            console.error("Error parsing JSON:", e);
            return str;
        }
    }
    return str;
}

function mergeCurrentAndRollbackData(currentRows, rollbackRows, dimensions) {
  const diffArray = [];
  const unchangedArray = [];
  const processedKeys = new Set();

  // First, process rollback rows
  rollbackRows.forEach(rollbackRow => {
    const dimensionKey = dimensions.map(dim => rollbackRow[dim]).join('|');
    processedKeys.add(dimensionKey);

    const matchingCurrentRow = currentRows.find(currentRow => 
      dimensions.every(dim => rollbackRow[dim] == currentRow[dim])
    );

    const rowData = {
      newValue: rollbackRow.newValue,
      currentValue: matchingCurrentRow === undefined ? "-": matchingCurrentRow.currentValue,
      ...dimensions.reduce((acc, dim) => ({
        ...acc,
        [dim]: rollbackRow[dim]
      }), {})
    };

    rowData.isSame = compareInputs(rowData.currentValue, rowData.newValue);

    // If values are different, add to diffArray, else add to unchangedArray
    if (!rowData.isSame) {
      diffArray.push(rowData);
    } else {
      unchangedArray.push(rowData);
    }
  });

  // Add any current rows that weren't in rollback data (these are always changes)
  currentRows.forEach(currentRow => {
    const dimensionKey = dimensions.map(dim => currentRow[dim]).join('|');

    if (!processedKeys.has(dimensionKey)) {
      diffArray.push({
        newValue: "-",
        currentValue: currentRow.currentValue,
        isSame: false,
        ...dimensions.reduce((acc, dim) => ({
          ...acc,
          [dim]: currentRow[dim]
        }), {})
      });
    }
  });

  // Combine arrays with changes first, followed by unchanged values
  return [...diffArray, ...unchangedArray];
}

// formatValue is a helper function to format values
function formatValue(valueObj) {
  if (valueObj === null) return "null";

  const valueType = valueObj.value;

  if (valueType === "float_value_v2") {
    return valueObj[valueType];
  }

  if (valueType === "float_array_value_v2") {
    return `[${valueObj[valueType].float_values_v2}]`;
  }

  if (valueType.includes("array")) {
    const baseType = valueType.split("_array_value")[0];
    const values = valueObj[valueType][`${baseType}_values`];
    return Array.isArray(values) ? JSON.stringify(values) : `[${values}]`;
  }

  return valueObj[valueType];
}

function isValidJsonString(str) {
  try {
    JSON.parse(str);
    return true;
  } catch (e) {
    return false;
  }
}

function compareInputs(input1, input2) {
  // Convert input1 to a string if it's not already
  const str1 = typeof input1 === 'string' ? input1 : JSON.stringify(input1);
  // Convert input2 to a string if it's not already
  const str2 = typeof input2 === 'string' ? input2 : JSON.stringify(input2);

  // Check if both strings are valid JSON
  const isValidJson1 = isValidJsonString(str1);
  const isValidJson2 = isValidJsonString(str2);

  // If both are valid JSON, parse and compare them
  if (isValidJson1 && isValidJson2) {
    const parsed1 = JSON.parse(str1);
    const parsed2 = JSON.parse(str2);
    return JSON.stringify(parsed1) === JSON.stringify(parsed2);
  }

  // If not both are valid JSON, compare the strings directly
  return str1 === str2;
}

return fetchAllData();
